--- 文件: D:\LLM\memory\agentmemory\src\state\hybrid-search.ts (第 242 至 324 行，共 324 行) ---
 242 |   private diversifyBySession(
 243 |     results: Array<{
 244 |       obsId: string;
 245 |       sessionId: string;
 246 |       bm25Score: number;
 247 |       vectorScore: number;
 248 |       graphScore: number;
 249 |       combinedScore: number;
 250 |       graphContext?: string;
 251 |     }>,
 252 |     limit: number,
 253 |     maxPerSession = 3,
 254 |   ): typeof results {
 255 |     const selected: typeof results = [];
 256 |     const sessionCounts = new Map<string, number>();
 257 | 
 258 |     for (const r of results) {
 259 |       const count = sessionCounts.get(r.sessionId) || 0;
 260 |       if (count >= maxPerSession) continue;
 261 |       selected.push(r);
 262 |       sessionCounts.set(r.sessionId, count + 1);
 263 |       if (selected.length >= limit) break;
 264 |     }
 265 | 
 266 |     if (selected.length < limit) {
 267 |       for (const r of results) {
 268 |         if (selected.length >= limit) break;
 269 |         if (!selected.some(s => s.obsId === r.obsId)) {
 270 |           selected.push(r);
 271 |         }
 272 |       }
 273 |     }
 274 | 
 275 |     return selected;
 276 |   }
 277 | 
 278 |   private async enrichResults(
 279 |     results: Array<{
 280 |       obsId: string;
 281 |       sessionId: string;
 282 |       bm25Score: number;
 283 |       vectorScore: number;
 284 |       graphScore: number;
 285 |       combinedScore: number;
 286 |       graphContext?: string;
 287 |     }>,
 288 |     limit: number,
 289 |   ): Promise<HybridSearchResult[]> {
 290 |     const sliced = results.slice(0, limit);
 291 |     const observations = await Promise.all(
 292 |       sliced.map(async (r) => {
 293 |         const obs = await this.kv
 294 |           .get<CompressedObservation>(KV.observations(r.sessionId), r.obsId)
 295 |           .catch(() => null);
 296 |         if (obs) return obs;
 297 |         // Fallback: indexed entry may originate from mem::remember, which
 298 |         // writes to KV.memories with a synthetic sessionId ("memory" or the
 299 |         // memory's first associated session). Coerce the Memory record into
 300 |         // a CompressedObservation so search/recall surface saved memories.
 301 |         const mem = await this.kv
 302 |           .get<Memory>(KV.memories, r.obsId)
 303 |           .catch(() => null);
 304 |         return mem ? memoryToObservation(mem) : null;
 305 |       }),
 306 |     );
 307 |     const enriched: HybridSearchResult[] = [];
 308 |     for (let i = 0; i < sliced.length; i++) {
 309 |       const obs = observations[i];
 310 |       if (obs) {
 311 |         enriched.push({
 312 |           observation: obs,
 313 |           bm25Score: sliced[i].bm25Score,
 314 |           vectorScore: sliced[i].vectorScore,
 315 |           graphScore: sliced[i].graphScore,
 316 |           combinedScore: sliced[i].combinedScore,
 317 |           sessionId: sliced[i].sessionId,
 318 |           graphContext: sliced[i].graphContext,
 319 |         });
 320 |       }
 321 |     }
 322 |     return enriched;
 323 |   }
 324 | }
--- 读取完毕 ---

